class Solution {
    public List<String> removeSubfolders(String[] folder) {
        List<String> result = new ArrayList<>();
        for (String folderItem : folder) {
            String[] parts = folderItem.split("/");
            for (String part : parts) {
                if (part.startsWith("/")) {
                    result.add(part.substring(1));
                }
            }
        }
        return result;
    }
}
